sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);


	function TestCase_GetPackageDependencyList(vPackage, vExpected)
	{
		function TestCase_GetPackageDependencyList_CheckResult(vInput,vExpected,vResult)
		{
			if (vExpected === false)
			{
				return (vExpected == vResult);
			}
			var aPackages = GetArrayValue(vResult);
			if (GetValue(vExpected,'count') != aPackages.length)
			{
				test.Log('Unexpected package count.');
				return false;
			}
			if (GetValue(vExpected,'dependency_status_summary') != GetValue(aPackages,aPackages.length-1,'dependency_status_summary'))
			{
				test.Log('Unexpected dependency status summary.');
				return false;
			}
			return true;
		}

		test.TestCase(
			'Function GetPackageDependencyList()',
			GetPackageDependencyList,
			{
				'Package': vPackage
			},
			vExpected,
			TestCase_GetPackageDependencyList_CheckResult);
	}

	TestCase_GetPackageDependencyList(null,false);
	TestCase_GetPackageDependencyList('',false);
	TestCase_GetPackageDependencyList('x_snc_devtools',{ count: 1, dependency_status_summary: 'ok' });
	
	AppCreate('Test Alpha','scoped','x_test_alpha');
	var grAppAlpha = GetAppRecord('x_test_alpha');
	TestCase_GetPackageDependencyList('x_test_alpha',{ count: 1, dependency_status_summary: 'ok' });

	AppCreate('Test Beta','scoped','x_test_beta');
	var grAppBeta = GetAppRecord('x_test_beta');
	TestCase_GetPackageDependencyList('x_test_beta',{ count: 1, dependency_status_summary: 'ok' });


	AppCreate('Test Gamma','scoped','x_test_gamma');
	var grAppGamma = GetAppRecord('x_test_gamma');
	TestCase_GetPackageDependencyList('x_test_gamma',{ count: 1, dependency_status_summary: 'ok' });


	var grDependency = new GlideRecord('x_snc_devtools_dependency');
	grDependency.initialize();
	grDependency.sys_scope = grAppAlpha.sys_id;
	grDependency.dependency = grAppBeta.sys_id;
	grDependency.insert();
	test.Log(grDependency);
	test.Log('');	
	TestCase_GetPackageDependencyList('x_test_alpha',{ count: 2, dependency_status_summary: 'ok' });		

	var grDependency = new GlideRecord('x_snc_devtools_dependency');
	grDependency.initialize();
	grDependency.sys_scope = grAppAlpha.sys_id;
	grDependency.dependency = grAppGamma.sys_id;
	grDependency.versions = '1000.0.0';
	grDependency.insert();
	test.Log(grDependency);
	test.Log('');		
	TestCase_GetPackageDependencyList('x_test_alpha',{ count: 3, dependency_status_summary: 'incompatible_version' });
	
	
	var grDependency = new GlideRecord('x_snc_devtools_dependency');
	grDependency.initialize();
	grDependency.sys_scope = grAppAlpha.sys_id;
	grDependency.dependency = GetPseudoSysId();
	grDependency.name = 'Pseudo';
	grDependency.insert();
	test.Log(grDependency);
	test.Log('');		
	TestCase_GetPackageDependencyList('x_test_alpha',{ count: 4, dependency_status_summary: 'missing' });
	
	// "Test Beta" now also has a dependency to "Pseudo" - so two different packages depend on the same package and duplicates are removed
	var grDependency = new GlideRecord('x_snc_devtools_dependency');
	grDependency.initialize();
	grDependency.sys_scope = grAppBeta.sys_id;
	grDependency.dependency = GetPseudoSysId();
	grDependency.name = 'Pseudo';
	grDependency.insert();
	test.Log(grDependency);
	test.Log('');		
	TestCase_GetPackageDependencyList('x_test_alpha',{ count: 4, dependency_status_summary: 'missing' });	

	// "Test Beta" now has a dependency to "Test Alpha" - this would be a circular dependency which is not allowed!  
	var grDependency = new GlideRecord('x_snc_devtools_dependency');
	grDependency.initialize();
	grDependency.sys_scope = grAppBeta.sys_id;
	grDependency.dependency = grAppAlpha.sys_id;
	grDependency.insert();
	test.Log(grDependency);
	test.Log('');		
	TestCase_GetPackageDependencyList('x_test_alpha',{ count: 5, dependency_status_summary: 'circular' });
	
	
	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
